RECV_BUFFER = 1024

QUEUE_SIZE = 50

sigma_logger = logging.getLogger('SIGMA.core.RTP')
DEV_MODE = GLOBALCONFIG.getDevMode()

def isIPv6(ipAddress):
  if ':' in ipAddress:
    return True
  else:
    return False

def RTPHeader(version, extension, CSRC_count, marker, payload_type, sequence_number, time_stamp, SSRC):
  byte1 = bytes([((version & 0x3) << 6) | ((extension & 0x1) << 4) | ((CSRC_count & 0xf) << 0)])
  byte2 = bytes([payload_type])
  byte3 = struct.pack(">H", sequence_number & 0xffff)
  byte4 = struct.pack(">L", time_stamp)
  byte5 = struct.pack(">L", SSRC)
  return byte1 + byte2 + byte3 + byte4 + byte5


class BaseFileStreamer(threading.Thread, object):
  runThread = True
  def __init__(self, thread_name):
    threading.Thread.__init__(self, name=thread_name)
    self.dataQueue = queue.Queue(QUEUE_SIZE)

  def stop(self):
    #print "[AudioFileStreamer] stop"
    self.runThread = False

  def getNextPacket(self):
    return self.dataQueue.get(True, 1)

  def openFileName(self, filename):  # returns the file name in the Sigma directory structure
    if DEV_MODE:
      sigma_logger.debug("current working directory: %s", os.getcwd())
    if filename[0] != '/':  # meaning it is not an absolute path
      try:  # try returning the filename with the added path
        return open("/opt/sigma/media/" + filename, 'rb')
      except IOError:  # we will try with the original file name as second chance - an exception here will not be captured
        pass
    return open(filename, 'rb')  # try with the original file name if it is an absolute path or if the completed path failed


class AudioFileStreamer(BaseFileStreamer):
  def __init__(self, filename, startTimeStamp, SSRC, ptime=20):#, payloadType=8, payloadLength=0):
    super().__init__("AudioFileStreamer")
    self.filename = filename
    self.startTimeStamp = startTimeStamp
    self.SSRC = SSRC
    self.ptime_ms = int(ptime)
    self.timeStampDelta = int(8 * self.ptime_ms)
    if "g729" in filename:
      self.payloadLength = int(self.timeStampDelta / 8)
      self.payloadType = 18
    elif "g711u" in filename:
      self.payloadLength = self.timeStampDelta
      self.payloadType = 0
    else:
      self.payloadLength = self.timeStampDelta
      self.payloadType = 8
    if DEV_MODE:
      sigma_logger.debug("[AudioFileStreamer] initialized with filename=%s, startTimestamp=%s, SSRC=%s, ptime=%f", self.filename, self.startTimeStamp, self.SSRC, self.ptime_ms*0.001)

  def run(self):
    if DEV_MODE:
      sigma_logger.debug("[AudioFileStreamer] running")
    sequenceNumber = 0
    timeStamp = self.startTimeStamp
    timePlay = 0  # time (ms) at which packets should be played
    audioFile = self.openFileName(self.filename)
    nextPacket = time.time() + self.ptime_ms * 0.001
    #print "[AudioFileStreamer] start"
    #first packet
    #one sample = 1 byte, so 160 samples = 160 bytes, etc...
    #audioData = audioFile.read(self.timeStampDelta)
    audioData = audioFile.read(self.payloadLength)
    #packetData = RTPHeader.build(Container(version=2,extension=0,CSRC_count=0,marker=0,payload_type=8,sequence_number=sequenceNumber,time_stamp=timeStamp,SSRC=self.SSRC)) + audioData
    packetData = (timePlay, timeStamp, sequenceNumber, self.SSRC, RTPHeader(2, 0, 0, 0, self.payloadType, sequenceNumber, timeStamp, self.SSRC) + audioData)
    while (self.runThread):
      try:
        self.dataQueue.put(packetData, True, 1)
        audioData = audioFile.read(self.payloadLength)
        #back to beginning of file if all read
        if len(audioData) != self.payloadLength:
          audioFile.seek(0)
          audioData = audioFile.read(self.payloadLength)
        sequenceNumber = sequenceNumber + 1
        timeStamp = timeStamp + self.timeStampDelta
        timePlay = timePlay + self.ptime_ms
        packetData = (timePlay, timeStamp, sequenceNumber, self.SSRC,
                      RTPHeader(2, 0, 0, 0, self.payloadType, sequenceNumber, timeStamp, self.SSRC) + audioData)
      except queue.Full:
        # If the queue is full we skip everything and we retry putting the same packet,
        # sleeping for the ptime (which is the interval between two packets).
        time.sleep(self.ptime_ms * 0.001)
        pass
    if DEV_MODE:
      sigma_logger.debug("[AudioFileStreamer] stopped")


class TelephoneEventStreamer(object):
  def __init__(self, event, volume, duration, payloadType):
    self.event = event
    self.duration = duration * 8000
    self.volume = volume
    self.firstTimeStamp = 0
    self.progressDuration = 0
    self.payloadType = payloadType
    if DEV_MODE:
      sigma_logger.debug("[TelephoneEventStreamer] initialized")
  def getNextReplacementPacket(self, timeStamp, sequenceNumber, SSRC):
    if not self.firstTimeStamp:
      self.firstTimeStamp = timeStamp
    if (self.progressDuration < self.duration):
      self.progressDuration = timeStamp - self.firstTimeStamp
      if (self.progressDuration >= self.duration):
        endOfEvent = 1
      else:
        endOfEvent = 0
      data = chr(int(self.event)) + chr(((endOfEvent & 0x1) << 7) | (self.volume & 0x3f)) + struct.pack(">H", self.progressDuration)[:2]
      packetData = RTPHeader(2, 0, 0, 0, self.payloadType, sequenceNumber, timeStamp, SSRC) + data
      return packetData
    else:
      return None


class ToneStreamer(object):
  def __init__(self, payloadType, frequency, volume=1.0, duration=2.0):
    self.firstTimeStamp = 0
    self.progressDuration = 0
    self.payloadType = payloadType
    self.data = ""
    #generate samples (duration * 8000 Hz)
    for i in range(int(duration * 8000)):
      sinSignal = math.sin(2*math.pi*frequency*float(i)/8000)
      sample = sinSignal * volume * 127
      self.data += audioop.lin2alaw(sample, 1)
  def getNextReplacementPacket(self, timeStamp, sequenceNumber, SSRC):
    if len(self.data) > 160:
      packetData = RTPHeader(2, 0, 0, 0, self.payloadType, sequenceNumber, timeStamp, SSRC) + data[:160]
      self.data = self.data
      return packetData
    else:
      return None


# Plays RTP packets with the given SSRC (Sync Source id) and payloadType
# at the times corresponding to the ones given in the .pcap file.
class CaptureFileStreamer(BaseFileStreamer):
  def __init__(self, filename, startTimeStamp, SSRC, payloadType):
    super().__init__("CaptureFileStreamer")
    self.filename = filename
    self.startTimeStamp = startTimeStamp
    self.SSRC = SSRC
    self.payloadType = payloadType
    self.startSeqNumber = 0
    self.startTimePlay = None

  def next_rtp_packet(self):
    # decode packet
    while True:
      try:
        (pkt_timeplay_s, pkt_buf) = next(self.pcap_iter)  # get data and time of replay (following the timestamp of the capture)
      except StopIteration:
        return None
      ethpkt = dpkt.ethernet.Ethernet(pkt_buf)
      if isinstance(ethpkt.data, dpkt.ip.IP):
        ip = ethpkt.data
        if isinstance(ip.data, dpkt.udp.UDP):
          udp = ip.data
          # extract RTP header data from the packet for verification
          try:
            (pkt_head, pkt_seqnumber, pkt_timestamp, pkt_ssrc) = struct.unpack('>HHLL', udp.data[0:12])
          except:  # if we can't unpack, the packet is too small, we continue
            continue
          pkt_version = pkt_head >> 14
          pkt_payload_type = pkt_head & 0x7f
          # check this is RTP (we can only check that the version number matches, and perhaps add a check on the payload type)
          if pkt_version != 2:
            continue
          # check SSRC matches or accept the first SSRC
          if self.SSRC is None:
            self.SSRC = pkt_ssrc
          if pkt_ssrc != self.SSRC:
            continue
          # check SSRC matches or accept the first SSRC
          if self.payloadType is None:
            self.payloadType = pkt_payload_type
          if pkt_payload_type != self.payloadType:
            continue
          # adjust timeplay
          if self.startTimePlay is None:
            self.startTimePlay = pkt_timeplay_s
          pkt_timeplay_s -= self.startTimePlay
          if pkt_ssrc == self.SSRC and pkt_payload_type == self.payloadType:
            # we pass all the udp data which constitute the RTP packet, including the RTP header.
            return_value = (pkt_timeplay_s * 1000.0, pkt_timestamp, self.startSeqNumber, self.SSRC, udp.data)
            self.startSeqNumber = self.startSeqNumber + 1
            return return_value

  def run(self):
    captureFile = self.openFileName(self.filename)
    pcap = dpkt.pcap.Reader(captureFile)
    self.pcap_iter = pcap.__iter__()  # packet iterator

    packet = self.next_rtp_packet()
    if packet is None:
      # no packets
      return
    (timeplay, timestamp, startSeqNumber, SSRC, rtpData) = packet
    # zero the starting time at the first packet
    timeplay_zero = timeplay
    timeplay = timeplay - timeplay_zero
    while self.runThread:
      try:
        # queue current packet
        self.dataQueue.put((timeplay, timestamp, startSeqNumber, SSRC, rtpData), True, 1)
        packet = self.next_rtp_packet()
        if packet is None:  # do not loop (the structure should be modified for this)
          break
        (timeplay, timestamp, startSeqNumber, SSRC, rtpData) = packet
        timeplay = timeplay - timeplay_zero
      except queue.Full:
        # If the queue is full we skip everything and we retry putting the same packet, after sleeping for 1 ms
        time.sleep(0.001)
        pass


class RTPGenericStreamer(threading.Thread, object):
  runThread = True
  def __init__(self, localIP, localPort, remoteIP, remotePort, resSocket=None):
    threading.Thread.__init__(self)
    self.localIP = localIP
    self.localPort = localPort
    self.remoteIP = remoteIP
    self.remotePort = remotePort
    self.manageSocket = (resSocket is None)
    if resSocket:
      self.s = resSocket
      self.localIP = self.s.getsockname()[0]
      self.localPort = self.s.getsockname()[1]
      if DEV_MODE:
        sigma_logger.debug("[RTPGenericStreamer] socket provided for port %i", self.localPort)
    else:
      if isIPv6(localIP):
        self.s = socket.socket(socket.AF_INET6, socket.SOCK_DGRAM)
      else:
        self.s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
      self.s.bind((localIP, self.localPort))
      if DEV_MODE:
        sigma_logger.debug("[RTPGenericStreamer] socket not provided for port %i", self.localPort)
    # OROU : example of code to set TOS at socket level, not tested at aall
    #self.s.setsockopt(socket.IPPROTO_TCP, socket.IP_TOS, tos_value), see https://en.wikipedia.org/wiki/Type_of_service
    self.c = self.s
    self.replacementStreamer = None
    if DEV_MODE:
      sigma_logger.debug("[RTPGenericStreamer] initialized")

  def newDialog(self):
    return Dialog(self.connector)

  def dtmf(self, event, volume, duration, payloadType):
    self.replacementStreamer = TelephoneEventStreamer(event, volume, duration, payloadType)

  def start(self):
    try:
      threading.Thread.start(self)
    except:
      sigma_logger.exception("An error occured during the start of the RTP thread")
      raise

  def stream(self, afs):
    try:
      afs.start()
    except:
      sigma_logger.exception("An error occured during starting of the RTP streaming, unable to open AFS")
      return
    startTime = time.time()
    firstPacket = True
    if DEV_MODE:
      sigma_logger.debug("[RTPGenericStreamer] really started")
    try:
      while (self.runThread):
        try:
          (timePlay, timeStamp, sequenceNumber, SSRC, data) = afs.getNextPacket()
          if firstPacket:
            timePlay_zero = timePlay
            firstPacket = False
          timePlay = timePlay - timePlay_zero  # zero time of play at start of RTP
        except queue.Empty:
          # if we didn't get a packet, try again (don't sleep here), and log a warning.
          sigma_logger.warning("No RTP data to stream")
          continue
        if self.replacementStreamer:
          replacementData = self.replacementStreamer.getNextReplacementPacket(timeStamp, sequenceNumber, SSRC)
          if replacementData:
            data = replacementData
          else:
            self.replacementStreamer = None
        currTime = time.time()
        waitTime = startTime - currTime + timePlay * 0.001  # time to wait before sending packet
        if waitTime > 0:
            #time.sleep(nextPacket - time.time() + (random.uniform(0.0, 0.03) - 0.0015))
            #time.sleep(nextPacket - time.time() + (random.uniform(0.0, 0.003) - 0.0015))
            time.sleep(waitTime)
        self.c.sendto(data, 0, (self.remoteIP, self.remotePort))
        while True:  # there is no guarantee that for every packet sent we get a single packet. Especially with strangely crafted RTPs
          try:
            # avoid recvfrom if no data available.
            (r, w, x) = select.select([self.c], [], [], 0)
            if self.c in r:
              (temp_data, address) = self.c.recvfrom(RECV_BUFFER)
            else:
              break
          except Exception as ex:
            sigma_logger.debug(f"RTP streaming exception on recv: {repr(ex)}")
            break
    except Exception as e:
      if self.runThread:
        sigma_logger.exception(f"An error occured during the RTP streaming - {repr(e)}")
      else:
        sigma_logger.debug(f"An error occured during the RTP streaming while the RTP streamer was supposed to stop - {repr(e)}")
      #self.stop()
    afs.stop()
    try:
      if DEV_MODE:
        sigma_logger.debug("[RTPGenericStreamer] start close process for port %i", self.localPort)
      if self.manageSocket:
        sigma_logger.debug("[RTPGenericStreamer] Managing socket.")
        self.s.close()
      else:
        sigma_logger.debug("[RTPGenericStreamer] Socket is managed externally.")
      if DEV_MODE:
        sigma_logger.debug("[RTPGenericStreamer] closed port: %i", self.localPort)
    except: # protection in case the socket would have been already closed
      sigma_logger.warning("[RTPGenericStreamer] port close process failed, already stoped before? port: %i", self.localPort)
      pass

  def stop(self):
    if DEV_MODE:
      sigma_logger.debug("[RTPGenericStreamer] stop request")
    self.runThread = False


class RTPCaptureStreamer(RTPGenericStreamer):
  def __init__(self, localIP, localPort, remoteIP, remotePort, captureFile, SSRC=None, payloadType=None, resSocket=None):
    super().__init__(localIP, localPort, remoteIP, remotePort, resSocket)
    self.captureFile = captureFile
    self.SSRC = SSRC
    self.payloadType = payloadType
    if DEV_MODE:
      sigma_logger.debug("[RTPCaptureStreamer] initialized")

  def run(self):
    if DEV_MODE:
      sigma_logger.debug("[RTPCaptureStreamer] running")
    try:
      afs = CaptureFileStreamer(self.captureFile, 0, self.SSRC, self.payloadType)
    except:
      sigma_logger.exception("An error occured during starting of the RTP streaming, unable to open AFS")
      return
    self.stream(afs)


class RTPStreamer(RTPGenericStreamer):
  def __init__(self, localIP, localPort, remoteIP, remotePort, audioFile="test3.g711a", ptime=20, resSocket=None):
    super().__init__(localIP, localPort, remoteIP, remotePort, resSocket)
    self.audioFile = audioFile
    self.ptime = float(ptime)/1000
    if DEV_MODE:
      sigma_logger.debug("[RTPStreamer] initialized")

  def run(self):
    if DEV_MODE:
      sigma_logger.debug("[RTPStreamer] running")
    try:
      afs = AudioFileStreamer(self.audioFile, 0, random.randint(0, 0xff), self.ptime * 1000)
    except:
      sigma_logger.exception("An error occured during starting of the RTP streaming, unable to open AFS")
      return
    self.stream(afs)

